This method should be simplified a bunch (a little pseudocode-y):
```
std::string schema;
std::string url;
if (endpoint.startswith("unix://")) {
  schema = "unix";
  url = endpoint.lstrip("unix://")
} else if (endpoint.startswith("/")) {
  // I would only support absolute unix paths.
  schema = "unix";
  url = endpoint;
} else if (endpoint.startswith("tcp://")) {
  schema = "tcp";
  url = endpoint.lstrip("tcp://");
} else {
  schema = "tcp";
  url = endpoint;
}

if (scheme == "unix") {
  // I don't think we need the windows ifdef here? This code path should not be called on windows, right?
  return boost::asio::local::stream_protocol::endpoint(url);
}
if (scheme == "tcp") {
  // The ScanToken stuff, but let's make ScanToken a private method and not encourage use outside of this file.
  // Also let's use std::stoi for the port parsing.
}
```

