```
# in loss() call this 
loss = self._masked_loss(preds, targets, masks)
# fn definition
def _masked_loss(preds, targets, masks):
     for key in targets:
           assert key not in preds, 'for target {key} there is no prediction named from the output of the model'
           if self._is_discrete(key):
                loss += self.config[f'loss_coef_{key}'] * self._masked_xent_loss(preds[key], targets[key], masks)
           else:
                loss += self.config[f'loss_coef_{key}'] * self._masked_mse_loss(preds[key], targets[key], masks)

     return loss

def _is_discrete(self, key):
     return key == SampleBatch.Action and self.action_space.is_discrete
```

